struct Info {
	Info() :
		sum(0), 
		mxpre(0), mnpre(0), 
		mxsuf(0), mnsuf(0), 
		mxsub(0), mnsub(0)
	{}
	Info(int x) :
		sum(x), 
		mxpre(max(0, x)), mnpre(min(0, x)), 
		mxsuf(max(0, x)), mnsuf(min(0, x)), 
		mxsub(max(0, x)), mnsub(min(0, x))
	{}

	int sum;	      // 整个区间和
	int mxpre, mnpre; // 最大/最小前缀和
	int mxsuf, mnsuf; // 最大/最小后缀和
	int mxsub, mnsub; // 最大/最小子段和
};
Info operator+(const Info& lower, const Info& upper) {
	// 合并 下半段(lower) 和 上半段(upper)
	Info res;
	res.sum = lower.sum + upper.sum;
	res.mxpre = max(upper.mxpre, upper.sum + lower.mxpre);
	res.mnpre = min(upper.mnpre, upper.sum + lower.mnpre);
	res.mxsuf = max(lower.mxsuf, lower.sum + upper.mxsuf);
	res.mnsuf = min(lower.mnsuf, lower.sum + upper.mnsuf);
	res.mxsub = max({
		upper.mxsub, lower.mxsub,
		upper.sum + lower.mxpre - upper.mnpre,
		lower.sum + upper.mxsuf - lower.mnsuf
		});
	res.mnsub = min({
		upper.mnsub, lower.mnsub,
		upper.sum + lower.mnpre - upper.mxpre,
		lower.sum + upper.mnsuf - lower.mxsuf
		});
	return res;
}

void solve(int CASE)
{
	int n; cin >> n;
	var dep = vector<int>(n + 2);
	var p = Vec2<int>(n + 2, 21);

	var lca = [&dep, &p](int x, int y)->int {
		if (dep[x] < dep[y])swap(x, y);
		for (int i = 20; i >= 0; i--)
			if (dep[x] - (1 << i) >= dep[y])
				x = p[x][i];
		if (x == y) return x;
		for (int i = 20; i >= 0; i--)
			if (p[x][i] != p[y][i])
				x = p[x][i], y = p[y][i];
		return p[x][0];
		};
	dep[1] = 1;
	p[1][0] = 0;

	var dp = Vec2<Info>(n + 2, 21);
	dp[1][0] = 1;

	int siz = 1;
	while (n--) {
		char op; cin >> op;
		if (op == '+') {
			int v, x; cin >> v >> x;
			int now = ++siz;

			dep[now] = dep[v] + 1;
			p[now][0] = v;

			dp[now][0] = x;
			for (int i = 1; (1 << i) <= dep[now]; i++) {
				p[now][i] = p[p[now][i - 1]][i - 1];
				dp[now][i] = dp[now][i - 1] + dp[p[now][i - 1]][i - 1];
			}
		}
		else {
			var jump = [&](int now, int cha)->Info {
				Info res;
				fa(i, 0, 20)if (cha & (1 << i)) {
					res = res + dp[now][i];
					now = p[now][i];
				}
				return res;
				};
			var reverse = [](Info a)->Info {
				swap(a.mxpre, a.mxsuf);
				swap(a.mnpre, a.mnsuf);
				return a;
				};

			int x, y, k; cin >> x >> y >> k;
			int l = lca(x, y);

			Info res;
			if (l == y)res = jump(x, dep[x] - dep[l] + 1);
			else if (l == x)res = jump(y, dep[y] - dep[l] + 1);
			else res = jump(x, dep[x] - dep[l] + 1) + reverse(jump(y, dep[y] - dep[l]));

			if (k >= res.mnsub and k <= res.mxsub)cout << "YES" << endl;
			else cout << "NO" << endl;
		}
	}
	return;
}
